import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React, { useState } from 'react';
import { usePrevious } from './usePrevious';

function Harness() {
  const [count, setCount] = useState(0);
  const prev = usePrevious(count);
  return (
    <div>
      <span data-testid="current">{count}</span>
      <span data-testid="previous">{prev === undefined ? 'none' : String(prev)}</span>
      <button data-testid="increment" onClick={() => setCount(c => c + 1)}>+</button>
    </div>
  );
}

function StringHarness() {
  const [name, setName] = useState('Alice');
  const prev = usePrevious(name);
  return (
    <div>
      <span data-testid="current">{name}</span>
      <span data-testid="previous">{prev === undefined ? 'none' : prev}</span>
      <button data-testid="change" onClick={() => setName('Bob')}>Change</button>
    </div>
  );
}

describe('usePrevious', () => {
  it('returns undefined on first render', () => {
    render(<Harness />);
    expect(screen.getByTestId('previous')).toHaveTextContent('none');
  });

  it('returns the previous value after an update', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('increment'));
    expect(screen.getByTestId('current')).toHaveTextContent('1');
    expect(screen.getByTestId('previous')).toHaveTextContent('0');
  });

  it('tracks multiple updates', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('increment'));
    expect(screen.getByTestId('current')).toHaveTextContent('3');
    expect(screen.getByTestId('previous')).toHaveTextContent('2');
  });

  it('works with string values', () => {
    render(<StringHarness />);
    expect(screen.getByTestId('previous')).toHaveTextContent('none');
    fireEvent.click(screen.getByTestId('change'));
    expect(screen.getByTestId('current')).toHaveTextContent('Bob');
    expect(screen.getByTestId('previous')).toHaveTextContent('Alice');
  });
});

